#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10,M=4e5+10,mod=998244853;

int T,n,m,s,t,q;
int head[N],rh[N],ver[M],edge[M],nxt[M],tot;
int dis[N],d[N],cs[N],ct[N],ds[N][2],fs[N],ft[N],last[N],cnt,sum[N][2],ans;
bool vis[N];

void add(int u,int v,int w){
    ver[++tot]=v,edge[tot]=w,nxt[tot]=head[u],head[u]=tot;
    ver[++tot]=u,edge[tot]=w,nxt[tot]=rh[v],rh[v]=tot;
}

int main(){
    scanf("%d",&T);
    while(T--){
        scanf("%d%d%d%d%d",&n,&m,&s,&t,&q);
        s++,t++;
        memset(head,0,sizeof(head));
        memset(rh,0,sizeof(rh));
        memset(d,0,sizeof(d));
        memset(cs,0,sizeof(cs));
        memset(ct,0,sizeof(ct));
        memset(dis,0x3f,sizeof(dis));
        tot=1;
        for(int i=1,u,v,w;i<=m;i++){
            scanf("%d%d%d",&u,&v,&w);
            u++,v++;
            add(u,v,w);
        }
        queue<int> qu;

        qu.push(s);
        memset(vis,0,sizeof(vis));
        vis[s]=1;
        while(qu.size()){
            int x=qu.front();
            qu.pop();
            for(int i=head[x];i;i=nxt[i]){
                d[ver[i]]++;
                if(!vis[ver[i]]){
                    vis[ver[i]]=1;
                    qu.push(ver[i]);
                }
            }
        }
        if(!vis[t]){
            puts("-1");
            continue;
        }

        qu.push(s),dis[s]=0,cs[s]=1;
        while(qu.size()){
            int x=qu.front();
            qu.pop();
            for(int i=head[x],y;i;i=nxt[i]){
                y=ver[i];
                if(dis[x]+edge[i]<dis[y])
                    dis[y]=dis[x]+edge[i],last[y]=i;
                cs[y]=(cs[y]+cs[x])%mod;
                if(!--d[y])
                    qu.push(y);
            }
        }

        qu.push(t);
        memset(vis,0,sizeof(vis));
        vis[t]=1;
        while(qu.size()){
            int x=qu.front();
            qu.pop();
            for(int i=rh[x];i;i=nxt[i]){
                d[ver[i]]++;
                if(!vis[ver[i]]){
                    vis[ver[i]]=1;
                    qu.push(ver[i]);
                }
            }
        }

        qu.push(t),ct[t]=1;
        while(qu.size()){
            int x=qu.front();
            qu.pop();
            for(int i=rh[x],y;i;i=nxt[i]){
                y=ver[i];
                ct[y]=(ct[y]+ct[x])%mod;
                if(!--d[y])
                    qu.push(y);
            }
        }

        memset(ds,0,sizeof(ds));
        cnt=1;
        for(int i=t,tp=0;i!=s;i=ver[last[i]^1]){
            int nxt=ver[last[i]^1];
            int xs=(1LL*cs[nxt]*ct[i]%mod==cs[t]);
            if(tp!=xs){
                cnt+=tp;
                tp=xs;
            }
            ds[cnt][tp]+=edge[last[i]];
        }

        ans=0;
        for(int i=1;i<=cnt;i++){
            sum[i][0]=sum[i-1][0]+ds[i][0];
            sum[i][1]=sum[i-1][1]+ds[i][1];
        }
        for(int i=1,j=0;i<=cnt;i++){
            while(sum[i][0]+sum[i][1]-sum[j][0]-sum[j][1]>q)
                j++;
            fs[i]=max(fs[i-1],sum[i][1]-sum[j][1]+min(q-(sum[i][0]+sum[i][1]-sum[j][0]-sum[j][1]),ds[j][1]));
        }
        ft[cnt+1]=0;
        for(int i=cnt,j=cnt;i;i--){
            while(sum[j][0]+sum[j][1]-sum[i][0]-sum[i-1][1]>q)
                j--;
            if(j>=i)
                ft[i]=max(ft[i+1],sum[j][1]-sum[i-1][1]+max(0,min(ds[j+1][1],q-(sum[j][0]+sum[j][1]-sum[i][0]-sum[i-1][1])-ds[j+1][0])));
            else
                ft[i]=q;
            ans=max(ans,fs[i]+ft[i+1]);
        }
        for(int i=1,j=0;i<=cnt;i++){
            while(sum[i][0]+sum[i][1]-sum[j][0]-sum[j][1]>2*q)
                j++;
            fs[i]=max(fs[i-1],sum[i][1]-sum[j][1]+min(2*q-(sum[i][0]+sum[i][1]-sum[j][0]-sum[j][1]),ds[j][1]));
        }
        ans=max(ans,fs[cnt]);
        printf("%d\n",sum[cnt][1]-ans);
    }
    return 0;
}
